import json
lines = open('ios_crash.ips').readlines()
crash = json.loads(''.join(lines[1:]))

# Check for additional crash fields that might contain more info
for key in ['extMods', 'vmSummary', 'storeInfo', 'crashReporterKey', 'modelCode', 'cpuType', 'isCorpse']:
    if key in crash:
        val = crash[key]
        if isinstance(val, str) and len(val) > 200:
            print(f'{key}: {val[:200]}...')
        else:
            print(f'{key}: {val}')

# Check lastExceptionBacktrace details
lebt = crash.get('lastExceptionBacktrace')
if lebt:
    print(f'lastExceptionBacktrace: {len(lebt)} frames')

# Check for nsexception info
print('asi:', json.dumps(crash.get('asi', {})))

# Look for any other fields with 'exception' in name
for key in crash:
    if 'exception' in key.lower():
        val = crash[key]
        if isinstance(val, dict):
            print(f'{key}: {json.dumps(val)}')
        else:
            print(f'{key}: {val}')
